  1→import { useState, useEffect, useMemo } from 'react';
  2→import {
  3→  BarChart,
  4→  Bar,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  Legend,
 10→  ResponsiveContainer,
 11→} from 'recharts';
 12→import type { LegendPayload } from 'recharts/types/component/DefaultLegendContent';
 13→import type { LoanSummary, AmortizationResult } from '../../types/loan';
 14→import { formatCurrency, formatCurrencyShort } from '../../utils/formatters';
 15→
 16→interface Props {
 17→  summary: LoanSummary;
 18→  simulatedResult?: AmortizationResult | null;
 19→}
 20→
 21→const getInitialMobile = () => (typeof window !== 'undefined' ? window.innerWidth < 640 : false);
 22→
 23→const useIsMobile = () => {
 24→  const [isMobile, setIsMobile] = useState(getInitialMobile);
 25→  useEffect(() => {
 26→    let timeout: ReturnType<typeof setTimeout>;
 27→    const check = () => {
 28→      clearTimeout(timeout);
 29→      timeout = setTimeout(() => setIsMobile(window.innerWidth < 640), 150);
 30→    };
 31→    window.addEventListener('resize', check);
 32→    return () => {
 33→      clearTimeout(timeout);
 34→      window.removeEventListener('resize', check);
 35→    };
 36→  }, []);
 37→  return isMobile;
 38→};
 39→
 40→const BAR_COLORS = {
 41→  Original: { fill: '#64748b', label: 'Original (No Prepayments)' },
 42→  Actual: { fill: '#2563eb', label: 'Actual (With Prepayments)' },
 43→  Simulated: { fill: '#d97706', label: 'Simulated' },
 44→} as const;
 45→
 46→const PATTERNS = {
 47→  Original: 'pattern-original',
 48→  Actual: 'pattern-actual',
 49→  Simulated: 'pattern-simulated',
 50→} as const;
 51→
 52→const ChartPatterns = () => (
 53→  <defs>
 54→    <pattern id={PATTERNS.Original} patternUnits="userSpaceOnUse" width="6" height="6">
 55→      <rect width="6" height="6" fill="#64748b" />
 56→    </pattern>
 57→    <pattern id={PATTERNS.Actual} patternUnits="userSpaceOnUse" width="6" height="6">
 58→      <rect width="6" height="6" fill="#2563eb" />
 59→      <line x1="0" y1="0" x2="6" y2="6" stroke="#1d4ed8" strokeWidth="1.5" />
 60→    </pattern>
 61→    <pattern id={PATTERNS.Simulated} patternUnits="userSpaceOnUse" width="6" height="6">
 62→      <rect width="6" height="6" fill="#d97706" />
 63→      <circle cx="3" cy="3" r="1" fill="#b45309" />
 64→    </pattern>
 65→  </defs>
 66→);
 67→
 68→interface CustomTooltipProps {
 69→  active?: boolean;
 70→  payload?: Array<{ name: string; value: number; color: string }>;
 71→  label?: string;
 72→}
 73→
 74→const CustomTooltip = ({ active, payload, label }: CustomTooltipProps) => {
 75→  if (!active || !payload?.length) return null;
 76→  return (
 77→    <div
 78→      role="tooltip"
 79→      className="rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-xs shadow-lg"
 80→    >
 81→      <p className="mb-1.5 font-semibold text-slate-700">{label}</p>
 82→      {payload.map((entry) => (
 83→        <div key={entry.name} className="flex items-center gap-2 py-0.5">
 84→          <span
 85→            className="inline-block h-2.5 w-2.5 rounded-sm"
 86→            style={{ backgroundColor: entry.color }}
 87→          />
 88→          <span className="text-slate-500">{entry.name}:</span>
 89→          <span className="font-medium text-slate-900">{formatCurrency(entry.value)}</span>
 90→        </div>
 91→      ))}
 92→    </div>
 93→  );
 94→};
 95→
 96→const renderLegend = (props: { payload?: readonly LegendPayload[] }) => {
 97→  const { payload } = props;
 98→  if (!payload) return null;
 99→  return (
100→    <div className="mt-2 flex flex-wrap items-center justify-center gap-x-4 gap-y-1 text-xs sm:text-sm">
101→      {payload.map((entry) => (
102→        <div key={String(entry.value)} className="flex items-center gap-1.5">
103→          <span
104→            className="inline-block h-2.5 w-2.5 rounded-sm sm:h-3 sm:w-3"
105→            style={{ backgroundColor: entry.color ?? '#94a3b8' }}
106→          />
107→          <span className="text-slate-600">{String(entry.value)}</span>
108→        </div>
109→      ))}
110→    </div>
111→  );
112→};
113→
114→export const ComparisonChart = ({ summary, simulatedResult }: Props) => {
115→  const isMobile = useIsMobile();
116→  const { withPrePayments: wp, withoutPrePayments: wop } = summary;
117→  const hasSimulated = !!simulatedResult;
118→
119→  const data = useMemo(
120→    () => [
121→      {
122→        name: 'Total Interest',
123→        Original: wop.totalInterest,
124→        Actual: wp.totalInterest,
125→        ...(simulatedResult ? { Simulated: simulatedResult.totalInterest } : {}),
126→      },
127→      {
128→        name: 'Total Paid',
129→        Original: wop.totalAmountPaid,
130→        Actual: wp.totalAmountPaid,
131→        ...(simulatedResult ? { Simulated: simulatedResult.totalAmountPaid } : {}),
132→      },
133→    ],
134→    [wop, wp, simulatedResult],
135→  );
136→
137→  const title = hasSimulated ? 'Original vs Actual vs Simulated' : 'Original vs Actual';
138→
139→  const ariaLabel = useMemo(() => {
140→    const parts = [
141→      `Loan comparison chart.`,
142→      `Total Interest: Original ${formatCurrency(wop.totalInterest)}, Actual ${formatCurrency(wp.totalInterest)}${hasSimulated ? `, Simulated ${formatCurrency(simulatedResult!.totalInterest)}` : ''}.`,
143→      `Total Paid: Original ${formatCurrency(wop.totalAmountPaid)}, Actual ${formatCurrency(wp.totalAmountPaid)}${hasSimulated ? `, Simulated ${formatCurrency(simulatedResult!.totalAmountPaid)}` : ''}.`,
144→    ];
145→    return parts.join(' ');
146→  }, [wop, wp, simulatedResult, hasSimulated]);
147→
148→  const interestSaved = wop.totalInterest - wp.totalInterest;
149→  const totalSaved = wop.totalAmountPaid - wp.totalAmountPaid;
150→
151→  return (
152→    <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm sm:p-6">
153→      <div className="mb-4 flex flex-col gap-1 sm:mb-5">
154→        <h3 className="text-base font-bold text-slate-900 sm:text-lg">{title}</h3>
155→        {interestSaved > 0 && (
156→          <p className="text-xs text-emerald-600 sm:text-sm">
157→            You save {formatCurrency(interestSaved)} in interest ({formatCurrency(totalSaved)}{' '}
158→            total)
159→          </p>
160→        )}
161→      </div>
162→
163→      {/* Accessible data table (visually hidden) */}
164→      <table className="sr-only" role="table" aria-label="Loan comparison data">
165→        <caption>Comparison of loan payment scenarios</caption>
166→        <thead>
167→          <tr>
168→            <th scope="col">Metric</th>
169→            <th scope="col">Original</th>
170→            <th scope="col">Actual</th>
171→            {hasSimulated && <th scope="col">Simulated</th>}
172→          </tr>
173→        </thead>
174→        <tbody>
175→          {data.map((row) => (
176→            <tr key={row.name}>
177→              <th scope="row">{row.name}</th>
178→              <td>{formatCurrency(row.Original)}</td>
179→              <td>{formatCurrency(row.Actual)}</td>
180→              {hasSimulated && <td>{formatCurrency(row.Simulated!)}</td>}
181→            </tr>
182→          ))}
183→        </tbody>
184→      </table>
185→
186→      <div role="img" aria-label={ariaLabel}>
187→        <ResponsiveContainer width="100%" height={isMobile ? 260 : 350}>
188→          <BarChart
189→            data={data}
190→            barCategoryGap="25%"
191→            margin={
192→              isMobile
193→                ? { left: -10, right: 5, top: 5, bottom: 5 }
194→                : { left: 0, right: 10, top: 5, bottom: 5 }
195→            }
196→          >
197→            <ChartPatterns />
198→            <CartesianGrid strokeDasharray="3 3" stroke="#e2e8f0" vertical={false} />
199→            <XAxis
200→              dataKey="name"
201→              tick={{ fontSize: isMobile ? 10 : 12, fill: '#475569' }}
202→              axisLine={{ stroke: '#cbd5e1' }}
203→              tickLine={false}
204→            />
205→            <YAxis
206→              tickFormatter={(v) => formatCurrencyShort(v)}
207→              width={isMobile ? 55 : 80}
208→              tick={{ fontSize: isMobile ? 10 : 12, fill: '#475569' }}
209→              axisLine={false}
210→              tickLine={false}
211→            />
212→            <Tooltip
213→              content={<CustomTooltip />}
214→              cursor={{ fill: 'rgba(148, 163, 184, 0.1)', radius: 4 }}
215→            />
216→            <Legend content={renderLegend} />
217→            <Bar dataKey="Original" fill={BAR_COLORS.Original.fill} radius={[6, 6, 0, 0]} />
218→            <Bar dataKey="Actual" fill={BAR_COLORS.Actual.fill} radius={[6, 6, 0, 0]} />
219→            {hasSimulated && (
220→              <Bar dataKey="Simulated" fill={BAR_COLORS.Simulated.fill} radius={[6, 6, 0, 0]} />
221→            )}
222→          </BarChart>
223→        </ResponsiveContainer>
224→      </div>
225→    </div>
226→  );
227→};
