31→export const PrincipalInterestChart = ({ schedule, isSimulated }: Props) => {
32→  const isMobile = useIsMobile();
33→  // For large schedules, sample every N months to keep chart readable
34→  const maxBars = isMobile ? 30 : 60;
35→  const step = schedule.length > maxBars ? Math.ceil(schedule.length / maxBars) : 1;
36→  const data = schedule
37→    .filter((_, i) => i % step === 0 || i === schedule.length - 1)
38→    .map((row) => ({
39→      month: row.month,
40→      date: formatDate(row.date),
41→      principal: row.principalComponent,
42→      interest: row.interestComponent,
43→    }));
44→
45→  return (
46→    <div className="rounded-2xl border border-slate-200 bg-white p-4 sm:p-6 shadow-sm">
47→      <h3 className="mb-3 sm:mb-4 text-base sm:text-lg font-bold text-slate-900">
48→        Principal vs Interest per EMI
49→        {isSimulated && (
50→          <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
51→        )}
52→      </h3>
53→      <ResponsiveContainer width="100%" height={isMobile ? 260 : 350}>
54→        <BarChart data={data} margin={isMobile ? { left: -10, right: 5, top: 5, bottom: 5 } : undefined}>
55→          <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
56→          <XAxis dataKey="month" tick={{ fontSize: isMobile ? 10 : 12 }} />
57→          <YAxis
58→            tickFormatter={(v) => formatCurrencyShort(v)}
59→            width={isMobile ? 45 : 80}
60→            tick={{ fontSize: isMobile ? 10 : 12 }}
61→          />
62→          <Tooltip
63→            formatter={(value) => formatCurrency(Number(value))}
64→            labelFormatter={(_: unknown, payload: readonly { payload?: { date?: string } }[]) =>
65→              payload?.[0]?.payload?.date || ''
66→            }
67→            contentStyle={{ fontSize: 12, borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}
68→          />
69→          <Legend
70→            iconSize={isMobile ? 8 : 14}
71→            wrapperStyle={{ fontSize: isMobile ? 10 : 12, paddingTop: 8 }}
72→          />
73→          <Bar dataKey="principal" name="Principal" stackId="a" fill="#22c55e" radius={[0, 0, 0, 0]} />
74→          <Bar dataKey="interest" name="Interest" stackId="a" fill="#ef4444" radius={[4, 4, 0, 0]} />
75→        </BarChart>
76→      </ResponsiveContainer>
77→    </div>
78→  );
79→};
