  1→import { useMemo, useState, useEffect } from 'react';
  2→import {
  3→  AreaChart,
  4→  Area,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  Legend,
 10→  ResponsiveContainer,
 11→} from 'recharts';
 12→import type { LoanSummary, AmortizationResult } from '../../types/loan';
 13→import { formatCurrency, formatCurrencyShort, formatDate } from '../../utils/formatters';
 14→
 15→interface Props {
 16→  summary: LoanSummary;
 17→  simulatedResult?: AmortizationResult | null;
 18→}
 19→
 20→const useIsMobile = () => {
 21→  const [isMobile, setIsMobile] = useState(false);
 22→  useEffect(() => {
 23→    const check = () => setIsMobile(window.innerWidth < 640);
 24→    check();
 25→    window.addEventListener('resize', check);
 26→    return () => window.removeEventListener('resize', check);
 27→  }, []);
 28→  return isMobile;
 29→};
 30→
 31→const buildCumulativeData = (summary: LoanSummary, simulatedResult?: AmortizationResult | null) => {
 32→  const { withPrePayments, withoutPrePayments } = summary;
 33→
 34→  const maxLen = Math.max(
 35→    withPrePayments.schedule.length,
 36→    withoutPrePayments.schedule.length,
 37→    simulatedResult?.schedule.length ?? 0,
 38→  );
 39→
 40→  let cumOriginal = 0;
 41→  let cumActual = 0;
 42→  let cumSimulated = 0;
 43→
 44→  return Array.from({ length: maxLen }, (_, i) => {
 45→    const dateStr =
 46→      withoutPrePayments.schedule[i]?.date ??
 47→      withPrePayments.schedule[i]?.date ??
 48→      simulatedResult?.schedule[i]?.date ??
 49→      '';
 50→
 51→    cumOriginal += withoutPrePayments.schedule[i]?.interestComponent ?? 0;
 52→    cumActual += withPrePayments.schedule[i]?.interestComponent ?? 0;
 53→    if (simulatedResult) {
 54→      cumSimulated += simulatedResult.schedule[i]?.interestComponent ?? 0;
 55→    }
 56→
 57→    const entry: Record<string, number | string> = {
 58→      month: i + 1,
 59→      label: dateStr ? formatDate(dateStr) : '',
 60→      original: Math.round(cumOriginal),
 61→      actual: Math.round(cumActual),
 62→    };
 63→    if (simulatedResult) {
 64→      entry.simulated = Math.round(cumSimulated);
 65→    }
 66→    return entry;
 67→  });
 68→};
 69→
 70→export const CumulativeInterestChart = ({ summary, simulatedResult }: Props) => {
 71→  const isMobile = useIsMobile();
 72→  const data = useMemo(
 73→    () => buildCumulativeData(summary, simulatedResult),
 74→    [summary, simulatedResult],
 75→  );
 76→
 77→  return (
 78→    <div className="rounded-2xl border border-slate-200 bg-white p-4 sm:p-6 shadow-sm">
 79→      <h3 className="mb-3 sm:mb-4 text-base sm:text-lg font-bold text-slate-900">Cumulative Interest</h3>
 80→      <ResponsiveContainer width="100%" height={isMobile ? 260 : 350}>
 81→        <AreaChart data={data} margin={isMobile ? { left: -10, right: 5, top: 5, bottom: 5 } : undefined}>
 82→          <defs>
 83→            <linearGradient id="gradOriginal" x1="0" y1="0" x2="0" y2="1">
 84→              <stop offset="5%" stopColor="#94a3b8" stopOpacity={0.3} />
 85→              <stop offset="95%" stopColor="#94a3b8" stopOpacity={0} />
 86→            </linearGradient>
 87→            <linearGradient id="gradActual" x1="0" y1="0" x2="0" y2="1">
 88→              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
 89→              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
 90→            </linearGradient>
 91→            <linearGradient id="gradSimulated" x1="0" y1="0" x2="0" y2="1">
 92→              <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
 93→              <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
 94→            </linearGradient>
 95→          </defs>
 96→          <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
 97→          <XAxis
 98→            dataKey="month"
 99→            tick={{ fontSize: isMobile ? 10 : 12 }}
100→            label={isMobile ? undefined : { value: 'Month', position: 'insideBottom', offset: -5 }}
101→          />
102→          <YAxis
103→            tickFormatter={(v) => formatCurrencyShort(v)}
104→            width={isMobile ? 55 : 80}
105→            tick={{ fontSize: isMobile ? 10 : 12 }}
106→          />
107→          <Tooltip
108→            formatter={(value) => formatCurrency(Number(value))}
109→            labelFormatter={(_: unknown, payload: readonly { payload?: { label?: string } }[]) =>
110→              payload?.[0]?.payload?.label || ''
111→            }
112→            contentStyle={{ fontSize: 12, borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}
113→          />
114→          <Legend
115→            iconSize={isMobile ? 8 : 14}
116→            wrapperStyle={{ fontSize: isMobile ? 10 : 12, paddingTop: 8 }}
117→          />
118→          <Area
119→            type="monotone"
120→            dataKey="original"
121→            name="Original"
122→            stroke="#94a3b8"
123→            fill="url(#gradOriginal)"
124→            strokeWidth={2}
125→          />
126→          <Area
127→            type="monotone"
128→            dataKey="actual"
129→            name="Actual"
130→            stroke="#ef4444"
131→            fill="url(#gradActual)"
132→            strokeWidth={2}
133→          />
134→          {simulatedResult && (
135→            <Area
136→              type="monotone"
137→              dataKey="simulated"
138→              name="Simulated"
139→              stroke="#f59e0b"
140→              fill="url(#gradSimulated)"
141→              strokeWidth={2}
142→              strokeDasharray="6 3"
143→            />
144→          )}
145→        </AreaChart>
146→      </ResponsiveContainer>
147→    </div>
148→  );
149→};
