 23→export const PaymentBreakupChart = ({ summary }: Props) => {
 24→  const isMobile = useIsMobile();
 25→  const { withPrePayments: wp } = summary;
 26→  const principalPaid = wp.totalAmountPaid - wp.totalInterest;
 27→
 28→  const data = [
 29→    { name: 'Principal', value: Math.round(principalPaid) },
 30→    { name: 'Interest', value: Math.round(wp.totalInterest) },
 31→  ];
 32→
 33→  const total = data[0].value + data[1].value;
 34→
 35→  const renderLabel = ({
 36→    cx,
 37→    cy,
 38→    midAngle,
 39→    innerRadius,
 40→    outerRadius,
 41→    index,
 42→  }: {
 43→    cx?: number;
 44→    cy?: number;
 45→    midAngle?: number;
 46→    innerRadius?: number;
 47→    outerRadius?: number;
 48→    index?: number;
 49→  }) => {
 50→    const RADIAN = Math.PI / 180;
 51→    const radius = (innerRadius ?? 0) + ((outerRadius ?? 0) - (innerRadius ?? 0)) * 0.5;
 52→    const x = (cx ?? 0) + radius * Math.cos(-(midAngle ?? 0) * RADIAN);
 53→    const y = (cy ?? 0) + radius * Math.sin(-(midAngle ?? 0) * RADIAN);
 54→    const pct = ((data[index ?? 0].value / total) * 100).toFixed(1);
 55→
 56→    return (
 57→      <text
 58→        x={x}
 59→        y={y}
 60→        fill="white"
 61→        textAnchor="middle"
 62→        dominantBaseline="central"
 63→        fontWeight="bold"
 64→        fontSize={isMobile ? 12 : 14}
 65→      >
 66→        {pct}%
 67→      </text>
 68→    );
 69→  };
 70→
 71→  return (
 72→    <div className="rounded-2xl border border-slate-200 bg-white p-4 sm:p-6 shadow-sm">
 73→      <h3 className="mb-3 sm:mb-4 text-base sm:text-lg font-bold text-slate-900">Payment Breakup</h3>
 74→      <ResponsiveContainer width="100%" height={isMobile ? 240 : 350}>
 75→        <PieChart>
 76→          <Pie
 77→            data={data}
 78→            cx="50%"
 79→            cy="50%"
 80→            outerRadius={isMobile ? 85 : 130}
 81→            innerRadius={isMobile ? 30 : 45}
 82→            dataKey="value"
 83→            labelLine={false}
 84→            label={renderLabel}
 85→          >
 86→            {data.map((_, index) => (
 87→              <Cell key={index} fill={COLORS[index]} />
 88→            ))}
 89→          </Pie>
 90→          <Tooltip
 91→            formatter={(value) => formatCurrency(Number(value))}
 92→            contentStyle={{ fontSize: 12, borderRadius: 12, border: '1px solid #e2e8f0', boxShadow: '0 4px 12px rgba(0,0,0,0.08)' }}
 93→          />
 94→        </PieChart>
 95→      </ResponsiveContainer>
 96→      <div className="mt-2 flex justify-center gap-4 sm:gap-6 text-xs sm:text-sm">
 97→        <span className="flex items-center gap-1.5">
 98→          <span className="inline-block h-3 w-3 rounded-full bg-green-500" />
 99→          Principal: {formatCurrency(principalPaid)}
100→        </span>
101→        <span className="flex items-center gap-1.5">
102→          <span className="inline-block h-3 w-3 rounded-full bg-red-500" />
103→          Interest: {formatCurrency(wp.totalInterest)}
104→        </span>
105→      </div>
106→    </div>
107→  );
108→};
