 1→import type { LoanInput, PrePayment, RateChange, LoanSummary } from '../types/loan';
 2→import { calculateAmortization } from './amortization';
 3→
 4→export const generateSummary = (
 5→  loan: LoanInput,
 6→  prePayments: PrePayment[],
 7→  rateChanges: RateChange[] = [],
 8→): LoanSummary => {
 9→  const withPrePayments = calculateAmortization(loan, prePayments, rateChanges);
10→  const withoutPrePayments = calculateAmortization(loan, [], rateChanges);
11→
12→  return {
13→    withPrePayments,
14→    withoutPrePayments,
15→    interestSaved:
16→      Math.round((withoutPrePayments.totalInterest - withPrePayments.totalInterest) * 100) / 100,
17→    monthsSaved: withoutPrePayments.totalMonths - withPrePayments.totalMonths,
18→  };
19→};
