114→export const ComparisonChart = ({ summary, simulatedResult }: Props) => {
115→  const isMobile = useIsMobile();
116→  const { withPrePayments: wp, withoutPrePayments: wop } = summary;
117→  const hasSimulated = !!simulatedResult;
118→
119→  const data = useMemo(
120→    () => [
121→      {
122→        name: 'Total Interest',
123→        Original: wop.totalInterest,
124→        Actual: wp.totalInterest,
125→        ...(simulatedResult ? { Simulated: simulatedResult.totalInterest } : {}),
126→      },
127→      {
128→        name: 'Total Paid',
129→        Original: wop.totalAmountPaid,
130→        Actual: wp.totalAmountPaid,
131→        ...(simulatedResult ? { Simulated: simulatedResult.totalAmountPaid } : {}),
132→      },
133→    ],
134→    [wop, wp, simulatedResult],
135→  );
136→
137→  const title = hasSimulated ? 'Original vs Actual vs Simulated' : 'Original vs Actual';
138→
139→  const ariaLabel = useMemo(() => {
140→    const parts = [
141→      `Loan comparison chart.`,
142→      `Total Interest: Original ${formatCurrency(wop.totalInterest)}, Actual ${formatCurrency(wp.totalInterest)}${hasSimulated ? `, Simulated ${formatCurrency(simulatedResult!.totalInterest)}` : ''}.`,
143→      `Total Paid: Original ${formatCurrency(wop.totalAmountPaid)}, Actual ${formatCurrency(wp.totalAmountPaid)}${hasSimulated ? `, Simulated ${formatCurrency(simulatedResult!.totalAmountPaid)}` : ''}.`,
144→    ];
145→    return parts.join(' ');
146→  }, [wop, wp, simulatedResult, hasSimulated]);
147→
148→  const interestSaved = wop.totalInterest - wp.totalInterest;
149→  const totalSaved = wop.totalAmountPaid - wp.totalAmountPaid;
150→
151→  return (
152→    <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm sm:p-6">
153→      <div className="mb-4 flex flex-col gap-1 sm:mb-5">
154→        <h3 className="text-base font-bold text-slate-900 sm:text-lg">{title}</h3>
155→        {interestSaved > 0 && (
156→          <p className="text-xs text-emerald-600 sm:text-sm">
157→            You save {formatCurrency(interestSaved)} in interest ({formatCurrency(totalSaved)}{' '}
158→            total)
159→          </p>
160→        )}
161→      </div>
162→
163→      {/* Accessible data table (visually hidden) */}
164→      <table className="sr-only" role="table" aria-label="Loan comparison data">
165→        <caption>Comparison of loan payment scenarios</caption>
166→        <thead>
167→          <tr>
168→            <th scope="col">Metric</th>
169→            <th scope="col">Original</th>
170→            <th scope="col">Actual</th>
171→            {hasSimulated && <th scope="col">Simulated</th>}
172→          </tr>
173→        </thead>
174→        <tbody>
175→          {data.map((row) => (
176→            <tr key={row.name}>
177→              <th scope="row">{row.name}</th>
178→              <td>{formatCurrency(row.Original)}</td>
179→              <td>{formatCurrency(row.Actual)}</td>
180→              {hasSimulated && <td>{formatCurrency(row.Simulated!)}</td>}
181→            </tr>
182→          ))}
183→        </tbody>
